namespace sv_20c2c2bd8a294d479aa35357884926bd.Models;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

using sv_20c2c2bd8a294d479aa35357884926bd.Models;

namespace sv_20c2c2bd8a294d479aa35357884926bd.Services;

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

using sv_20c2c2bd8a294d479aa35357884926bd.Models;

namespace sv_20c2c2bd8a294d479aa35357884926bd.Services;

public class MockChatService : IChatService
{
    private readonly List<Channel> _channels;
    private readonly List<Message> _messages;
    private int _nextMessageId;

    public MockChatService()
    {
        _channels = new()
        {
            new(1, "general", "General discussion for the team", 3),
            new(2, "engineering", "Engineering updates and technical discussions", 1),
            new(3, "design", "Design reviews and feedback", 0),
            new(4, "random", "Off-topic and fun stuff", 5),
            new(5, "announcements", "Important team announcements", 0),
        };

        _messages = new()
        {
            new(1, 1, "Alice", "Hey everyone! Welcome to the new chat app 🎉", DateTime.UtcNow.AddHours(-5), null, new() { new("🎉", new() { "Bob", "Carol" }), new("👋", new() { "Dave" }) }),
            new(2, 1, "Bob", "Thanks Alice! This looks great.", DateTime.UtcNow.AddHours(-4.5), null, new()),
            new(3, 1, "Carol", "Love the new design. Quick question — can we customize the sidebar?", DateTime.UtcNow.AddHours(-4), null, new() { new("👍", new() { "Alice" }) }),
            new(4, 1, "Alice", "Yes! We'll add theme support in the next sprint.", DateTime.UtcNow.AddHours(-3.5), 3, new()),
            new(5, 1, "Dave", "Has anyone looked at the performance metrics from last week?", DateTime.UtcNow.AddHours(-3), null, new()),
            new(6, 1, "Bob", "I did — the response times improved by 20% after the caching update.", DateTime.UtcNow.AddHours(-2.5), 5, new() { new("🚀", new() { "Alice", "Carol" }) }),
            new(7, 1, "Carol", "That's impressive! Great work on the caching layer.", DateTime.UtcNow.AddHours(-2), 5, new()),
            new(8, 1, "Dave", "Agreed, solid improvement. Let's keep monitoring.", DateTime.UtcNow.AddMinutes(-45), null, new()),
            new(9, 1, "Alice", "Sprint planning is at 2 PM today, don't forget!", DateTime.UtcNow.AddMinutes(-10), null, new() { new("✅", new() { "Bob", "Carol", "Dave" }) }),
            new(10, 2, "Bob", "Just pushed the new API endpoints for the dashboard.", DateTime.UtcNow.AddHours(-2), null, new()),
            new(11, 2, "Carol", "I'll review the PR this afternoon.", DateTime.UtcNow.AddHours(-1), null, new()),
            new(12, 2, "Alice", "Make sure we have integration tests before merging.", DateTime.UtcNow.AddMinutes(-30), 10, new() { new("👍", new() { "Bob" }) }),
        };

        _nextMessageId = _messages.Max(m => m.Id) + 1;
    }

    public Task<List<Channel>> GetChannelsAsync()
    {
        return Task.FromResult(_channels.ToList());
    }

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        var messages = _messages
            .Where(m => m.ChannelId == channelId && m.ReplyToId == null)
            .OrderByDescending(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .OrderBy(m => m.SentAt)
            .ToList();
        return Task.FromResult(messages);
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var message = new Message(_nextMessageId++, channelId, "You", content, DateTime.UtcNow, replyToId, new());
        _messages.Add(message);
        return Task.FromResult(message);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        var root = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (root == null) return Task.FromResult(new List<Message>());

        var replies = _messages
            .Where(m => m.ReplyToId == rootMessageId)
            .OrderBy(m => m.SentAt)
            .ToList();

        var thread = new List<Message> { root };
        thread.AddRange(replies);
        return Task.FromResult(thread);
    }

    public Task AddReactionAsync(int messageId, string emoji)
    {
        var message = _messages.FirstOrDefault(m => m.Id == messageId);
        if (message == null) return Task.CompletedTask;

        var idx = _messages.IndexOf(message);
        var reactions = message.Reactions.ToList();
        var existing = reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing != null)
        {
            if (!existing.Users.Contains("You"))
            {
                reactions.Remove(existing);
                reactions.Add(new Reaction(emoji, new List<string>(existing.Users) { "You" }));
            }
        }
        else
        {
            reactions.Add(new Reaction(emoji, new() { "You" }));
        }

        _messages[idx] = message with { Reactions = reactions };
        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
        return Task.CompletedTask;
    }
}

