+        var replies = _messages
+            .Where(m => m.ReplyToId == rootMessageId)
+            .OrderBy(m => m.SentAt)
+            .ToList();
+
+        var thread = new List<Message> { root };
+        thread.AddRange(replies);
+        return Task.FromResult(thread);
+    }
+
+    public Task AddReactionAsync(int messageId, string emoji)
+    {
+        var message = _messages.FirstOrDefault(m => m.Id == messageId);
+        if (message == null) return Task.CompletedTask;
+
+        var idx = _messages.IndexOf(message);
+        var reactions = message.Reactions.ToList();
+        var existing = reactions.FirstOrDefault(r => r.Emoji == emoji);
+        if (existing != null)
+        {
+            if (!existing.Users.Contains("You"))
+            {
+                reactions.Remove(existing);
+                reactions.Add(new Reaction(emoji, new List<string>(existing.Users) { "You" }));
+            }
+        }
+        else
+        {
+            reactions.Add(new Reaction(emoji, new() { "You" }));
+        }
+
+        _messages[idx] = message with { Reactions = reactions };
+        return Task.CompletedTask;
+    }
