<div class="thread-panel">
    <div class="thread-header">
        <h5>Thread</h5>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (ThreadMessages.Count > 0)
    {
        <div class="thread-root-quote">
            <span class="quote-author">@ThreadMessages[0].Author</span>
            <span class="quote-content">@ThreadMessages[0].Content</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in ThreadMessages.Skip(1))
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="author">@reply.Author</span>
                        <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>
    }

    <MessageInput Placeholder="Reply in thread..."
                  ButtonLabel="Reply"
                  OnSend="OnReply" />
</div>

@code {
    [Parameter] public List<Message> ThreadMessages { get; set; } = new();
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return sentAt.ToString("MMM d, h:mm tt");
    }
}
