@using sv_20c2c2bd8a294d479aa35357884926bd.Models

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h5>Channels</h5>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <div class="channel-item @(channel.Id == ActiveChannelId ? "active" : "")"
                 @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-info">
                    <span class="channel-name"># @channel.Name</span>
                    <span class="channel-desc">@TruncateDescription(channel.Description)</span>
                </div>
                @if (channel.UnreadCount > 0)
                {
                    <span class="unread-badge">@channel.UnreadCount</span>
                }
            </div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = new();
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private string TruncateDescription(string desc)
        => desc.Length > 40 ? desc[..37] + "..." : desc;
}

.channel-sidebar {
    height: 100%;
    background-color: #2b2d42;
    color: #edf2f4;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #3a3d56;
}

.sidebar-header h5 {
    margin: 0;
    font-size: 1rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #8d99ae;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.channel-item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 8px 16px;
    cursor: pointer;
    transition: background-color 0.15s;
    gap: 8px;
}

.channel-item:hover {
    background-color: #3a3d56;
}

.channel-item.active {
    background-color: #4a4e6e;
    border-left: 3px solid #ef233c;
    padding-left: 13px;
}

.channel-info {
    display: flex;
    flex-direction: column;
    min-width: 0;
    flex: 1;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-desc {
    font-size: 0.75rem;
    color: #8d99ae;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    background-color: #ef233c;
    color: white;
    border-radius: 10px;
    padding: 1px 7px;
    font-size: 0.75rem;
    font-weight: 700;
    flex-shrink: 0;
}

