toolArgs.file_text:
.message-bubble {
    position: relative;
    padding: 8px 16px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-bubble:hover {
    background-color: #f5f5f5;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #2b2d42;
}

.timestamp {
    font-size: 0.75rem;
    color: #8d99ae;
}

.message-content {
    font-size: 0.9rem;
    color: #333;
    line-height: 1.45;
    word-break: break-word;
}

.reaction-bar {
    display: flex;
    gap: 4px;
    margin-top: 6px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    background-color: #e8eaf0;
    border: 1px solid #d0d3dc;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background-color: #d0d3e8;
    border-color: #4a4e6e;
}

.thread-link {
    margin-top: 4px;
    font-size: 0.8rem;
    color: #4a4e6e;
    cursor: pointer;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
    color: #2b2d42;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: white;
    border: 1px solid #d0d0d0;
    border-radius: 6px;
    box-shadow: 0 2px 6px rgba(0, 0, 0, 0.1);
    overflow: hidden;
    z-index: 10;
}

.action-btn {
    border: none;
    background: none;
    padding: 4px 10px;
    font-size: 0.8rem;
    cursor: pointer;
    color: #555;
    white-space: nowrap;
}

.action-btn:hover {
    background-color: #f0f0f0;
    color: #2b2d42;
}

.emoji-picker {
    position: absolute;
    top: -12px;
    right: 180px;
    display: flex;
    gap: 2px;
    background: white;
    border: 1px solid #d0d0d0;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
    z-index: 20;
}

.emoji-option {
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.emoji-option:hover {
    background-color: #f0f0f0;
}

