@using sv_20c2c2bd8a294d479aa35357884926bd.Models

<div class="thread-panel">
    <div class="thread-header">
        <h5>Thread</h5>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (ThreadMessages.Count > 0)
    {
        <div class="thread-root-quote">
            <span class="quote-author">@ThreadMessages[0].Author</span>
            <span class="quote-content">@ThreadMessages[0].Content</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in ThreadMessages.Skip(1))
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="author">@reply.Author</span>
                        <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>
    }

    <MessageInput Placeholder="Reply in thread..."
                  ButtonLabel="Reply"
                  OnSend="OnReply" />
</div>

@code {
    [Parameter] public List<Message> ThreadMessages { get; set; } = new();
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return sentAt.ToString("MMM d, h:mm tt");
    }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    border-left: 1px solid #e0e0e0;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 14px 16px;
    border-bottom: 1px solid #e0e0e0;
    background: #fafafa;
    flex-shrink: 0;
}

.thread-header h5 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #2b2d42;
}

.close-btn {
    border: none;
    background: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #8d99ae;
    padding: 2px 6px;
    border-radius: 4px;
}

.close-btn:hover {
    background-color: #eee;
    color: #2b2d42;
}

.thread-root-quote {
    padding: 12px 16px;
    background: #f0f1f5;
    border-left: 3px solid #4a4e6e;
    margin: 12px;
    border-radius: 0 6px 6px 0;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.quote-author {
    font-weight: 700;
    font-size: 0.85rem;
    color: #2b2d42;
}

.quote-content {
    font-size: 0.85rem;
    color: #555;
    line-height: 1.4;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.thread-reply {
    padding: 8px 16px;
}

.thread-reply:hover {
    background-color: #f9f9f9;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-header .author {
    font-weight: 700;
    font-size: 0.85rem;
    color: #2b2d42;
}

.reply-header .timestamp {
    font-size: 0.72rem;
    color: #8d99ae;
}

.reply-content {
    font-size: 0.85rem;
    color: #333;
    line-height: 1.4;
}

