arguments.file_text:
@page "/chat"
@rendermode InteractiveServer
@using sv_20c2c2bd8a294d479aa35357884926bd.Models
@using sv_20c2c2bd8a294d479aa35357884926bd.Services
@using sv_20c2c2bd8a294d479aa35357884926bd.Components.Chat
@inject IChatService ChatService
@layout ChatLayout

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        ActiveChannelId="_activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <MessagePanel Channel="_activeChannel"
                          Messages="_messages"
                          ThreadReplyCounts="_threadReplyCounts"
                          OnLoadMore="LoadMoreMessages"
                          OnSendMessage="SendMessage"
                          OnOpenThread="OpenThread"
                          OnReact="AddReaction" />
        }
        else
        {
            <div class="no-channel">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_threadOpen)
    {
        <div class="chat-thread">
            <ThreadPanel ThreadMessages="_threadMessages"
                         OnClose="CloseThread"
                         OnReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = new();
    private List<Message> _messages = new();
    private List<Message> _threadMessages = new();
    private Dictionary<int, int> _threadReplyCounts = new();
    private Channel? _activeChannel;
    private int _activeChannelId;
    private bool _threadOpen;
    private int? _activeThreadRootId;
    private int _messageSkip;
    private const int PageSize = 50;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messageSkip = 0;
        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        await ChatService.MarkChannelReadAsync(channelId);
        _channels = await ChatService.GetChannelsAsync(); // refresh unread counts
        await ComputeThreadReplyCounts();
        CloseThread();
    }

    private async Task LoadMoreMessages()
    {
        _messageSkip += PageSize;
        var older = await ChatService.GetMessagesAsync(_activeChannelId, _messageSkip, PageSize);
        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            await ComputeThreadReplyCounts();
        }
    }

    private async Task SendMessage(string content)
    {
        var msg = await ChatService.SendMessageAsync(_activeChannelId, content, null);
        _messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        _activeThreadRootId = rootMessageId;
        _threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _activeThreadRootId = null;
        _threadMessages = new();
    }

    private async Task SendThreadReply(string content)
    {
        if (_activeThreadRootId is null) return;
        var reply = await ChatService.SendMessageAsync(_activeChannelId, content, _activeThreadRootId);
        _threadMessages.Add(reply);

        // Update reply count
        _threadReplyCounts[_activeThreadRootId.Value] =
            _threadReplyCounts.GetValueOrDefault(_activeThreadRootId.Value) + 1;
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to reflect reaction change
        _messages = await ChatService.GetMessagesAsync(_activeChannelId, 0, _messageSkip + PageSize);

        // Also refresh thread if open
        if (_threadOpen && _activeThreadRootId.HasValue)
        {
            _threadMessages = await ChatService.GetThreadAsync(_activeThreadRootId.Value);
        }
    }

    private async Task ComputeThreadReplyCounts()
    {
        _threadReplyCounts.Clear();
        foreach (var msg in _messages)
        {
            var thread = await ChatService.GetThreadAsync(msg.Id);
            var replyCount = thread.Count - 1; // exclude root
            if (replyCount > 0)
            {
                _threadReplyCounts[msg.Id] = replyCount;
            }
        }
    }
}

.chat-container {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
}

.chat-main.expanded {
    flex: 1;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

.no-channel {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #8d99ae;
    font-size: 1.1rem;
}

